example.code:
// Lead form submission
fbq('track', 'Lead', {
  value: 50.00,
  currency: 'USD'
});

// Purchase with dynamic value
fbq('track', 'Purchase', {
  value: 99.00,
  currency: 'USD',
  content_ids: ['prod_123'],
  content_type: 'product'
});

// Add to cart
fbq('track', 'AddToCart', {
  value: 49.99,
  currency: 'USD',
  content_ids: ['SKU123'],
  content_type: 'product'
});

const bizSdk = require('facebook-nodejs-business-sdk');
const { EventRequest, UserData, ServerEvent } = bizSdk;

async function sendPurchaseEvent(pixelId, accessToken, userData, purchaseData) {
  const user = (new UserData())
    .setEmail(userData.email_sha256)
    .setPhone(userData.phone_sha256)
    .setClientIpAddress(userData.ip)
    .setClientUserAgent(userData.user_agent);

  const event = (new ServerEvent())
    .setEventName('Purchase')
    .setEventTime(Math.floor(Date.now() / 1000))
    .setEventId(purchaseData.event_id)  // for deduplication with browser pixel
    .setUserData(user)
    .setCustomData({
      value: purchaseData.value,
      currency: purchaseData.currency,
      order_id: purchaseData.order_id
    })
    .setEventSourceUrl(purchaseData.page_url);

  const request = (new EventRequest(accessToken, pixelId))
    .setEvents([event]);

  return request.execute();
}
